raw_outputs.groq2:
{
  "preconditions": [
    "x must be a real number",
    "x must be finite"
  ],
  "postconditions": [
    "erf(x) is a real number between -1 and 1",
    "erf(x) is NaN if x is NaN"
  ],
  "edge_cases": [
    "erf(0) is 0",
    "erf(inf) is 1",
    "erf(-inf) is -1",
    "erf(NaN) is NaN"
  ]
}

